solution_code:
#include <iostream>

int main()
{
    int width = 0;
    int height = 0;
    int depth = 0;

    std::cin >> width >> height >> depth;

    std::cout << "Width: " << width << '\n';
    std::cout << "Height: " << height << '\n';
    std::cout << "Depth: " << depth << '\n';

    return 0;
}

